import React, { useEffect, useState, useMemo } from 'react';
import { Briefcase, AlertCircle, UserCheck, Target, Building2, BarChart3, PieChart as PieChartIcon, TrendingUp, Users, Filter, ChevronDown, RefreshCw, Award, X, MapPin, Printer, Calendar, Phone, BookOpen, Heart, Sparkles, Lightbulb, CheckCircle2, XCircle, Clock, ArrowUpRight, ArrowDownRight, Timer, LineChart as LineChartIcon } from 'lucide-react';
