                                    <button onClick={handleAddBusiness} className="flex-1 md:flex-initial flex items-center justify-center gap-2 bg-white text-gray-700 border border-gray-200 hover:border-purple-300 hover:text-purple-600 px-4 py-2.5 rounded-xl text-sm font-bold shadow-sm transition-all">
