                    {/* Legend */}
                    <div className="flex justify-center gap-4 mt-6 text-[10px] font-bold uppercase text-slate-400">
                        <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-red-500"></div>Low</div>
                        <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-amber-500"></div>Moderate</div>
                        <div className="flex items-center gap-1"><div className="w-2 h-2 rounded-full bg-emerald-500"></div>High Quality</div>
                    </div>
                </div>

                {/* Right: Analysis & Breakdown */}
                <div className="flex-1 flex flex-col">
                    <div className="bg-gradient-to-br from-indigo-50/90 to-blue-50/90 p-6 rounded-2xl border border-indigo-100 mb-4 flex-grow">
                        <div className="flex items-start gap-3 mb-3">
                            <Lightbulb className="text-indigo-600 mt-1" size={18} />
                            <div>
                                <h5 className="font-bold text-indigo-900 text-sm uppercase tracking-wide">System Interpretation</h5>
                                <span className={`text-xs font-bold px-2 py-0.5 rounded border inline-block mt-1 ${
                                    qualityAnalysis?.verdict === 'High Quality' ? 'bg-emerald-100 text-emerald-700 border-emerald-200' :
                                    qualityAnalysis?.verdict === 'Moderate Quality' ? 'bg-amber-100 text-amber-700 border-amber-200' :
                                    'bg-red-100 text-red-700 border-red-200'
                                }`}>
                                    {qualityAnalysis?.verdict || "Analysis Pending"}
                                </span>
                            </div>
                        </div>
                        {loadingInsights ? (
                            <div className="space-y-2 animate-pulse">
                                <div className="h-2 bg-indigo-200 rounded w-full"></div>
                                <div className="h-2 bg-indigo-200 rounded w-3/4"></div>
                                <div className="h-2 bg-indigo-200 rounded w-5/6"></div>
                            </div>
                        ) : (
                            <p className="text-sm text-slate-700 leading-relaxed font-medium">
                                {qualityAnalysis?.qualityInterpretation || "Data insufficient to generate quality analysis."}
                            </p>
                        )}
                    </div>

                    <div className="grid grid-cols-2 gap-3">
                        <div className="bg-white/60 p-3 rounded-xl border border-white/50 shadow-sm">
                            <span className="text-[10px] font-bold text-slate-400 uppercase">Employment Type</span>
                            <div className="font-bold text-slate-800 text-lg">
                                {analytics.employedCount > 0 ? Math.round((analytics.fullTimeCount / analytics.employedCount) * 100) : 0}% <span className="text-xs font-medium text-slate-500">Full-Time</span>
                            </div>
                        </div>
                        <div className="bg-white/60 p-3 rounded-xl border border-white/50 shadow-sm">
                            <span className="text-[10px] font-bold text-slate-400 uppercase">Comp. & Ben.</span>
                            <div className="font-bold text-slate-800 text-lg">
                                {analytics.employedCount > 0 ? Math.round((analytics.highSalaryCount / analytics.employedCount) * 100) : 0}% <span className="text-xs font-medium text-slate-500">Above Avg.</span>
                            </div>
                        </div>
                        <div className="bg-white/60 p-3 rounded-xl border border-white/50 shadow-sm">
                            <span className="text-[10px] font-bold text-slate-400 uppercase">Career Level</span>
                            <div className="font-bold text-slate-800 text-lg">
                                {analytics.employedCount > 0 ? Math.round((analytics.professionalLevelCount / analytics.employedCount) * 100) : 0}% <span className="text-xs font-medium text-slate-500">Pro Level</span>
                            </div>
                        </div>
                        <div className="bg-white/60 p-3 rounded-xl border border-white/50 shadow-sm">
                            <span className="text-[10px] font-bold text-slate-400 uppercase">Relevance</span>
                            <div className="font-bold text-slate-800 text-lg">
                                {analytics.alignmentRate.length > 0 && analytics.employedCount > 0
                                    ? Math.round((analytics.alignmentRate[0].value / analytics.employedCount) * 100)
