                        <TrendingUp className="absolute bottom-6 right-6 text-white/30 opacity-0 group-hover:opacity-100 transition-opacity" size={28} />
                    </div>
                ))}
            </div>

            {/* --- NEW: EMPLOYMENT QUALITY METER (Gauge + Analysis) --- */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl flex flex-col lg:flex-row gap-8">

                {/* Left Column: Gauge & Info */}
                <div className="flex-1 flex flex-col relative min-h-[300px] border-r border-indigo-50/50 pr-8">

                    {/* Header - Upper Left */}
                    <div className="flex items-start gap-3 mb-4">
                        <div className="p-2 bg-emerald-100 text-emerald-600 rounded-xl shadow-sm"><Gauge size={20}/></div>
                        <div>
                            <h4 className="font-bold text-slate-800 text-lg leading-tight">Employment Quality Score</h4>
                            <p className="text-[10px] text-slate-500 font-medium mt-1">Metric based on Alignment, Salary, Job Level, & Status</p>
                        </div>
                    </div>

                    {/* Legend - Top (Below Header) */}
                    <div className="flex gap-4 mb-4 text-[10px] font-bold uppercase text-slate-400 pl-1">
                        <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded-full bg-red-500"></div>Low</div>
                        <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded-full bg-amber-500"></div>Moderate</div>
                        <div className="flex items-center gap-1.5"><div className="w-2.5 h-2.5 rounded-full bg-emerald-500"></div>High Quality</div>
                    </div>

                    {/* Gauge Container - Centered in remaining space */}
                    <div className="flex-grow flex flex-col items-center justify-center relative -mt-4"> 
                        <div className="relative w-[300px] h-[160px]">
                            <ResponsiveContainer width="100%" height="100%">
                                <PieChart>
                                    <Pie
                                        dataKey="value"
                                        startAngle={180}
                                        endAngle={0}
                                        data={[
