                                                        </span>
                                                    </div>
                                                    <div className="w-full bg-slate-100 rounded-full h-2.5 overflow-hidden">
                                                        <div 
                                                            className={`h-full rounded-full transition-all duration-1000 ${isFaster ? 'bg-emerald-500' : 'bg-indigo-500'}`} 
                                                            style={{ width: `${Math.max(percentage, 5)}%` }}
                                                        ></div>
                                                    </div>
                                                </div>
                                            );
                                        })
                                    }
                                </div>
                            )}
                         </div>
                         <p className="text-[10px] text-slate-400 mt-4 text-center italic">*Green bars indicate faster than university average.</p>
                    </div>

                    {/* RIGHT: Job Level Distribution (Moved Here & Redesigned Header) */}
                    <div className="bg-white/50 rounded-2xl p-6 border border-white/60 flex flex-col h-full">
                        <div className="flex items-center gap-3 mb-6">
                            <div className="p-2 bg-purple-100 text-purple-600 rounded-lg"><Award size={16}/></div>
                            <div>
                                <h4 className="font-bold text-slate-800 text-sm">Job Level Distribution</h4>
                                <p className="text-[10px] text-slate-500">Current career standing of graduates</p>
                            </div>
                        </div>

                        <div className="flex-grow flex items-center justify-center relative min-h-[250px]">
                            {analytics.jobLevelData.length > 0 ? (
                                <ResponsiveContainer width="100%" height={250}>
                                    <PieChart>
                                        <Pie
                                            data={analytics.jobLevelData}
                                            cx="50%"
                                            cy="50%" // Moved lower to prevent top cropping
                                            innerRadius={0} // Full Pie
                                            outerRadius={90}
                                            dataKey="value"
                                            label={renderCustomizedLabel}
                                            labelLine={false}
                                        >
                                            {analytics.jobLevelData.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={JOB_LEVEL_COLORS[index % JOB_LEVEL_COLORS.length]} stroke="white" strokeWidth={2} />
                                            ))}
                                        </Pie>
                                        <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', backgroundColor: 'rgba(255, 255, 255, 0.9)' }} />
                                        <Legend 
                                            verticalAlign="bottom" 
                                            height={36} 
                                            iconType="circle"
                                            formatter={(value) => <span className="text-xs font-bold text-slate-600">{value}</span>}
                                            wrapperStyle={{ paddingTop: '20px' }} // Pushed down
                                        />
                                    </PieChart>
                                </ResponsiveContainer>
                            ) : (
                                <div className="text-center text-slate-400">
                                    <AlertCircle className="mx-auto mb-2 opacity-50" />
                                    <p className="text-xs font-bold">No Data</p>
                                </div>
                            )}
                        </div>
                    </div>
                </div>

                {/* Combined Interpretation for Employment Journey */}
                <InterpretationBlock text={interpretations?.employmentJourney} loading={loadingInsights} />
            </div>

            {/* PROGRAM TO CAREER ALIGNMENT (Landscape) */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl">
                <div className="flex flex-col lg:flex-row gap-8 mb-4">

                    {/* Left: Alignment Chart */}
                    <div className="flex-1 flex flex-col justify-between">
                        <div>
                            <div className="flex items-center gap-3 mb-6">
                                <div className="p-2 bg-indigo-100 text-indigo-600 rounded-xl"><Target size={20}/></div>
                                <h4 className="font-bold text-slate-800">Program to Career Alignment</h4>
                            </div>

                            <div className="flex-grow flex items-center justify-center relative min-h-[250px]">
                                <ResponsiveContainer width="100%" height={250}>
                                    <PieChart>
                                        <Pie
                                            data={analytics.alignmentRate}
                                            cx="50%"
                                            cy="50%"
                                            innerRadius={60}
                                            outerRadius={80}
                                            paddingAngle={5}
                                            dataKey="value"
                                            stroke="none"
                                        >
                                            {analytics.alignmentRate.map((entry, index) => (
                                                <Cell key={`cell-${index}`} fill={ALIGNMENT_COLORS[index % ALIGNMENT_COLORS.length]} />
                                            ))}
                                        </Pie>
                                        <Tooltip contentStyle={{ borderRadius: '12px', border: 'none', backgroundColor: 'rgba(255, 255, 255, 0.9)' }} />
                                        <Legend 
                                            verticalAlign="bottom" 
                                            height={36} 
                                            iconType="circle"
                                            formatter={(value) => <span className="text-xs font-bold text-slate-600">{value}</span>}
                                        />
                                    </PieChart>
                                </ResponsiveContainer>
                                <div className="absolute inset-0 flex items-center justify-center pointer-events-none pb-8">
                                    <div className="text-center">
                                        <span className="text-4xl font-bold text-slate-800">
                                            {analytics.alignmentRate.length > 0 
                                                ? Math.round((analytics.alignmentRate[0].value / (analytics.alignmentRate[0].value + analytics.alignmentRate[1].value || 1)) * 100)
                                                : 0}%
                                        </span>
                                        <p className="text-xs text-indigo-500 font-bold uppercase">Aligned</p>
                                    </div>
                                </div>
                            </div>
                        </div>
                    </div>

                    {/* Divider for Desktop */}
                    <div className="hidden lg:block w-px bg-slate-200 my-4"></div>

                    {/* Right: Misalignment Reasons (Inner Card) */}
                    <div className="flex-1">
                         {analytics.alignmentRate.find(a => a.name === 'Non-Related' && a.value > 0) ? (
                            <div className="h-full flex flex-col bg-purple-50/40 rounded-2xl border border-purple-100 p-5 shadow-sm relative overflow-hidden">
                                 {/* Decorative bg blob */}
                                 <div className="absolute -right-4 -top-4 w-24 h-24 bg-purple-200/20 rounded-full blur-xl pointer-events-none"></div>

                                 <div className="flex items-center gap-3 mb-4 relative z-10">
                                    <div className="p-2 bg-white text-purple-600 rounded-xl shadow-sm border border-purple-50"><PieChartIcon size={20}/></div>
                                    <div>
                                        <h4 className="font-bold text-slate-800 text-sm">Job Misalignment Reasons</h4>
                                        <p className="text-[10px] text-slate-500 font-medium">Why graduates take non-related jobs</p>
                                    </div>
                                </div>

                                 {/* Embedded List */}
                                 <div className="flex-grow relative z-10">
                                    <ReasonListCard 
                                        title="" 
                                        icon={PieChartIcon}
                                        data={analytics.alignmentReasonData}
                                        colorClass=""
                                        barColorClass=""
                                        embedded={true}
                                    />
                                 </div>
                            </div>
                        ) : (
                            <div className="h-full flex flex-col items-center justify-center text-slate-400 opacity-50 p-6 bg-slate-50/50 rounded-2xl border border-slate-100">
                                <CheckCircle2 size={48} className="mb-2"/>
                                <p className="font-bold">100% Alignment Achieved</p>
                            </div>
                        )}
                    </div>
                </div>

                {/* Shared Interpretation */}
                <InterpretationBlock text={interpretations?.alignment} loading={loadingInsights} />
            </div>

            {/* INDUSTRY CHART (Leftover from previous grid) */}
            <div className="bg-white/40 backdrop-blur-xl border border-white/50 shadow-lg shadow-indigo-500/5 p-6 rounded-3xl flex flex-col justify-between">
                <div>
                    <div className="flex items-center gap-3 mb-6">
                        <div className="p-2 bg-blue-100 text-blue-600 rounded-xl"><BarChart3 size={20}/></div>
                        <h4 className="font-bold text-slate-800">Top 5 Industries</h4>
                    </div>
                    <div className="h-64 w-full">
                        <ResponsiveContainer width="100%" height="100%">
                            <BarChart layout="vertical" data={analytics.industryData} margin={{ top: 5, right: 30, left: 20, bottom: 5 }}>
                                <CartesianGrid strokeDasharray="3 3" horizontal={true} vertical={false} opacity={0.3} />
                                <XAxis type="number" hide />
                                <YAxis dataKey="name" type="category" width={100} tick={{fontSize: 12, fill: '#475569', fontWeight: 'bold'}} />
                                <Tooltip 
                                    contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 10px 15px -3px rgba(0, 0, 0, 0.1)', backgroundColor: 'rgba(255, 255, 255, 0.9)' }} 
                                    cursor={{fill: '#f1f5f9'}} 
                                    formatter={(value: number, name: string, props: any) => {
                                        const total = analytics.totalRespondents || 1; // Avoid divide by zero
                                        // Calculate percentage relative to ALL employed if possible, but here we use total
                                        return [`${value} Graduates`, `Count`];
                                    }}
                                />
                                <Bar dataKey="value" fill="#6366f1" radius={[0, 4, 4, 0]} barSize={16}>
                                    <LabelList dataKey="value" position="right" style={{ fontSize: '11px', fontWeight: 'bold', fill: '#64748b' }} formatter={(val: any) => `${val} grads`} />
                                </Bar>
                            </BarChart>
                        </ResponsiveContainer>
                    </div>
                    <div className="mt-4 pt-4 border-t border-slate-100 flex justify-between items-center text-xs text-slate-500">
                            <span className="font-bold">Total Employed in Top 5 Industries:</span>
                            <span className="font-bold text-slate-700">{analytics.industryData.reduce((acc, curr) => acc + curr.value, 0)} Graduates</span>
                    </div>
                </div>
                <InterpretationBlock text={interpretations?.industry} loading={loadingInsights} />
            </div>

            {/* LIST CARDS SECTION (Glass) */}
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">

                <ReasonListCard 
                    title="Unemployment Reasons" 
                    icon={AlertCircle}
                    data={analytics.unemploymentReasonData}
                    colorClass="" 
                    barColorClass=""
                    interpretation={interpretations?.unemployment}
                />

                <ReasonListCard 
                    title="Retirement Reasons" 
                    icon={UserCheck}
                    data={analytics.retirementReasonData}
                    colorClass="" 
                    barColorClass="" 
                    interpretation={interpretations?.retirement}
                />

            </div>
        </>
        )}

        {/* === 2. EDUCATION TAB === */}
        {activeTab === 'education' && <EducationAnalytics />}

        {/* === 3. COMMUNITY TAB === */}
        {activeTab === 'community' && <CommunityAnalytics />}

        {/* === 4. SKILLS TAB === */}
        {activeTab === 'skills' && <SkillsAnalytics />}
    </div>

    {/* === GLASSMORPHISM MODAL (ENHANCED) === */}
    {selectedStatusDetail && (
            <div className="fixed inset-0 z-[9999] flex items-center justify-center print:p-0">
                <div 
                    className="absolute inset-0 bg-slate-200/60 backdrop-blur-3xl animate-in fade-in duration-300 no-print"
                    onClick={() => setSelectedStatusDetail(null)}
                ></div>
                <div id="printable-modal" className="bg-white/80 backdrop-blur-2xl rounded-3xl border border-white/60 shadow-2xl w-full max-w-7xl h-[85vh] relative z-10 flex flex-col animate-in zoom-in-95 duration-300 overflow-hidden ring-1 ring-white/40">
                    <div className="p-6 border-b border-white/40 flex justify-between items-center bg-white/40 backdrop-blur-md sticky top-0 z-20">
                        <div className="flex items-center gap-4">
                            <div className="p-4 bg-gradient-to-br from-indigo-500 to-purple-600 rounded-2xl text-white shadow-xl shadow-indigo-500/20 no-print">
                                {selectedStatusDetail === 'Employed' && <Briefcase size={28} />}
                                {selectedStatusDetail === 'Unemployed' && <AlertCircle size={28} />}
                                {selectedStatusDetail === 'Self-employed' && <Building2 size={28} />}
                                {selectedStatusDetail === 'Retired' && <UserCheck size={28} />}
                            </div>
                            <div>
                                <h3 className="text-3xl font-black text-slate-800 tracking-tight">{selectedStatusDetail} List</h3>
                                <p className="text-sm text-slate-500 font-bold mt-1">
                                    Showing <span className="text-indigo-600">{modalData.length} records</span> • {selectedYear === 'All' ? 'All Batches' : `Batch ${selectedYear}`} • {selectedCourse === 'All' ? 'All Programs' : 'Selected Program'}
                                </p>
                            </div>
                        </div>
                        <div className="flex items-center gap-3 no-print">
                            <button onClick={handlePrint} className="flex items-center gap-2 px-5 py-2.5 bg-slate-800 text-white rounded-xl text-sm font-bold shadow-lg hover:bg-slate-900 hover:shadow-xl hover:-translate-y-0.5 transition-all">
                                <Printer size={18} /> Print Report
                            </button>
                            <button onClick={() => setSelectedStatusDetail(null)} className="p-2.5 bg-white/60 border border-white/50 rounded-xl hover:bg-red-50 hover:text-red-500 hover:border-red-200 transition-all shadow-sm text-slate-400">
                                <X size={24} />
                            </button>
                        </div>
                    </div>

                    <div className="flex-grow overflow-auto p-0 bg-white/20">
                        {modalData.length === 0 ? (
                            <div className="flex flex-col items-center justify-center h-full text-slate-400 py-20">
                                <div className="p-6 bg-white/40 rounded-full mb-4">
                                    <Users size={48} className="opacity-50" />
                                </div>
                                <p className="font-bold text-lg">No records found matching current filters.</p>
                            </div>
                        ) : (
                            <div className="w-full">
                                <table className="w-full text-left border-collapse">
                                    <thead className="bg-slate-50/90 sticky top-0 z-10 backdrop-blur-md shadow-sm">
                                        <tr>
                                            <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50 w-1/4">Alumni Profile</th>
                                            {selectedStatusDetail === 'Employed' && (
                                                <>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Position & Level</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Company & Industry</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Details</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50 text-center">Alignment</th>
                                                </>
                                            )}
                                            {selectedStatusDetail === 'Self-employed' && (
                                                <>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Business Name & Type</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Address</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Duration</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50 text-center">Alignment</th>
                                                </>
                                            )}
                                            {selectedStatusDetail === 'Unemployed' && (
                                                <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Reason Provided</th>
                                            )}
                                            {selectedStatusDetail === 'Retired' && (
                                                <>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Retirement Info</th>
                                                    <th className="p-5 text-[11px] font-bold text-slate-500 uppercase tracking-widest border-b border-white/50">Previous Company</th>
                                                </>
                                            )}
                                        </tr>
                                    </thead>
                                    <tbody className="divide-y divide-indigo-50/50">
                                        {modalData.map((record, idx) => (
                                            <tr key={idx} className="hover:bg-indigo-50/40 transition-colors group">
                                                <td className="p-5 align-top">
                                                    <div className="flex items-start gap-3">
                                                        <div className="w-10 h-10 rounded-full bg-gradient-to-br from-slate-200 to-slate-300 flex items-center justify-center text-slate-600 font-bold text-xs shadow-inner">
                                                            {record.full_name.charAt(0)}
                                                        </div>
                                                        <div>
                                                            <div className="font-bold text-slate-800 text-sm">{record.full_name}</div>
                                                            <div className="text-xs text-slate-500 font-medium mt-0.5">{record.program}</div>
                                                            <div className="inline-block mt-2 px-2 py-0.5 bg-white border border-slate-200 text-slate-600 rounded text-[10px] font-bold shadow-sm">
                                                                Batch {record.year_level}
                                                            </div>
                                                        </div>
                                                    </div>
                                                </td>
                                                {selectedStatusDetail === 'Employed' && (
                                                    <>
                                                        <td className="p-5 align-top">
                                                            <div className="font-bold text-slate-700 text-sm">{record.current_position || 'N/A'}</div>
                                                            <div className="text-xs text-indigo-500 font-bold mt-1 flex items-center gap-1 bg-indigo-50 px-2 py-1 rounded w-fit">
                                                                <Award size={12} /> {record.current_job_level || 'Unclassified'}
                                                            </div>
                                                        </td>
                                                        <td className="p-5 align-top">
                                                            <div className="font-bold text-slate-700 text-sm">{record.company_name}</div>
                                                            <div className="text-xs text-slate-500 mt-1 flex items-center gap-1">
                                                                <Building2 size={12}/> {record.industry || 'N/A'}
                                                            </div>
                                                        </td>
                                                        <td className="p-5 align-top">
                                                            <div className="text-xs text-slate-600 space-y-1">
                                                                <div className="flex items-center gap-1"><MapPin size={12} className="text-slate-400"/> {record.company_address || 'N/A'}</div>
                                                                <div className="flex items-center gap-1"><Calendar size={12} className="text-slate-400"/> Hired: {record.date_hired || 'N/A'}</div>
                                                            </div>
                                                        </td>
                                                        <td className="p-5 align-top text-center">
                                                            <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-[10px] font-bold uppercase shadow-sm border ${
                                                                record.job_alignment === 'Related' 
                                                                ? 'bg-green-100 text-green-700 border-green-200' 
                                                                : 'bg-amber-100 text-amber-700 border-amber-200'
                                                            }`}>
                                                                {record.job_alignment === 'Related' ? <CheckCircle2 size={12}/> : <XCircle size={12}/>}
                                                                {record.job_alignment || 'N/A'}
                                                            </span>
                                                        </td>
                                                    </>
                                                )}
                                                 {selectedStatusDetail === 'Self-employed' && (
                                                    <>
                                                        <td className="p-5 align-top">
                                                            <div className="font-bold text-slate-700 text-sm">{record.business_name}</div>
                                                            <div className="text-xs text-slate-500 mt-1">{record.business_type || 'Type not specified'}</div>
                                                        </td>
                                                        <td className="p-5 align-top">
                                                            <div className="text-xs text-slate-600 flex items-center gap-1">
                                                                <MapPin size={12} className="text-slate-400"/> {record.business_address}
                                                            </div>
                                                        </td>
                                                        <td className="p-5 align-top">
                                                            <div className="text-xs text-slate-600 flex items-center gap-1">
                                                                <Clock size={12} className="text-slate-400"/> {record.business_duration}
                                                            </div>
                                                        </td>
                                                        <td className="p-5 align-top text-center">
                                                            <span className={`inline-flex items-center gap-1 px-3 py-1 rounded-full text-[10px] font-bold uppercase shadow-sm border ${
                                                                record.job_alignment === 'Related' 
                                                                ? 'bg-green-100 text-green-700 border-green-200' 
                                                                : 'bg-amber-100 text-amber-700 border-amber-200'
                                                            }`}>
                                                                {record.job_alignment === 'Related' ? <CheckCircle2 size={12}/> : <XCircle size={12}/>}
                                                                {record.job_alignment || 'N/A'}
                                                            </span>
                                                        </td>
                                                    </>
                                                )}
                                                {selectedStatusDetail === 'Unemployed' && (
                                                    <td className="p-5 align-top">
                                                        <div className="font-bold text-slate-700 bg-slate-50 px-3 py-2 rounded-lg inline-block border border-slate-200">
                                                            {record.unemployed_reasons}
                                                        </div>
                                                    </td>
                                                )}
                                                {selectedStatusDetail === 'Retired' && (
                                                    <>
                                                        <td className="p-5 align-top">
                                                            <div className="font-semibold text-slate-700">{record.retirement_reason}</div>
                                                            <div className="text-xs text-slate-500 mt-1">Retired: {record.date_retired}</div>
                                                        </td>
                                                        <td className="p-5 align-top">{record.last_company}</td>
                                                    </>
                                                )}
                                            </tr>
                                        ))}
                                    </tbody>
                                </table>
                            </div>
                        )}
                    </div>
                    <div className="p-4 bg-white/40 backdrop-blur-md border-t border-white/50 text-xs text-slate-500 text-center font-medium">
                        Confidential Report generated by Laguna University Alumni Tracer
                    </div>
                </div>
            </div>
        )}
    </>
  );
};

export default HomePage;
